static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

static bool is_valid_turbidity(int turbidity) {
    return (turbidity >= 0 && turbidity <= 35);
}

static bool is_valid_level(int level) {
    return (level >= 0 && level <= 100);
}

static void controller_set_clear_streak(controller_t *controller, int turbidity) {
    if (is_valid_turbidity(turbidity)) {
        controller->clear_streak_count++;
    } else {
        controller->clear_streak_count = 0;
    }
}

static void controller_set_drain_open_state(controller_t *controller, bool drain_open) {
    controller->drain_open = drain_open;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    bool previous_filter_on = controller->filter_on;
    bool previous_drain_open = controller->drain_open;
    controller_state_t previous_state = controller->state;

    /* Reset clear streak on any invalid input */
    if (input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        output.timed_out = false;
        return output;
    }

    /* Check timeout condition - if either sensor is stale for more than 1000ms, go to safe idle */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY && controller->last_turbidity_ms + CONTROLLER_SENSOR_TIMEOUT_MS > input.now_ms) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        output.timed_out = true;
        return output;
    }

    if (input.kind == CONTROLLER_INPUT_LEVEL && controller->last_level_ms + CONTROLLER_SENSOR_TIMEOUT_MS > input.now_ms) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        output.timed_out = true;
        return output;
    }

    /* Process valid inputs */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        /* Check clear streak condition */
        if (input.turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
            controller_set_clear_streak(controller, input.turbidity_ntu);
        } else {
            controller_set_clear_streak(controller, -1);
        }

        /* Check filter state based on turbidity */
        if (controller->clear_streak_count == 0) {
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_SAFE_IDLE;
            output.state_name = "STATE SAFE_IDLE";
            output.changed = true;
            output.timed_out = false;
        } else if (input.turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            /* Turbidity > 40 during clear streak - reset and go to filtering */
            controller->clear_streak_count = 0;
            output.filter_on = true;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_FILTERING;
            output.state_name = "STATE FILTERING";
            output.changed = true;
            output.timed_out = false;
        } else {
            /* Turbidity <= 35 during clear streak - increment clear streak */
            controller_set_clear_streak(controller, input.turbidity_ntu);
            if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Check settle timing - we need at least 400ms of settling */
                if (input.now_ms - controller->settling_started_ms < CONTROLLER_SETTLING_MS) {
                    output.filter_on = false;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_SAFE_IDLE;
                    output.state_name = "STATE SAFE_IDLE";
                    output.changed = true;
                    output.timed_out = false;
                } else if (input.turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU && input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    /* Reached clear and settle - drain open */
                    controller_set_drain_open_state(controller, true);
                    output.filter_on = false;
                    output.drain_open = true;
                    output.state = CONTROLLER_STATE_DRAINING;
                    output.state_name = "STATE DRAINING";
                    output.changed = true;
                    output.timed_out = false;
                } else {
                    /* Still in settling but not drained yet */
                    if (input.turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU && input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                        controller_set_clear_streak(controller, input.turbidity_ntu);
                        output.filter_on = false;
                        output.drain_open = false;
                        output.state = CONTROLLER_STATE_SAFE_IDLE;
                        output.state_name = "STATE SAFE_IDLE";
                        output.changed = true;
                        output.timed_out = false;
                    } else {
                        /* Turbidity > 35 or level < min during settling - reset streak */
                        controller->clear_streak_count = 0;
                        output.filter_on = false;
                        output.drain_open = false;
                        output.state = CONTROLLER_STATE_SAFE_IDLE;
                        output.state_name = "STATE SAFE_IDLE";
                        output.changed = true;
                        output.timed_out = false;
                    }
                }
            } else {
                /* Clear streak not yet reached but in filtering */
                if (input.turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller_set_clear_streak(controller, input.turbidity_ntu);
                } else {
                    controller->clear_streak_count = 0;
                }
                output.filter_on = true;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = "STATE FILTERING";
                output.changed = true;
                output.timed_out = false;
            }
        }

    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* Check filter state based on level */
        if (input.level < CONTROLLER_MIN_PROCESS_LEVEL) {
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_SAFE_IDLE;
            output.state_name = "STATE SAFE_IDLE";
            output.changed = true;
            output.timed_out = false;
        } else if (input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Check clear streak condition */
            if (controller->clear_streak_count == 0) {
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_SAFE_IDLE;
                output.state_name = "STATE SAFE_IDLE";
                output.changed = true;
                output.timed_out = false;
            } else if (input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Level >= min during clear streak - check for drain */
                controller_set_clear_streak(controller, input.level);
                if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                    input.now_ms - controller->settling_started_ms >= CONTROLLER_SETTLING_MS) {
                    /* Drain open after 400ms of settling */
                    controller_set_drain_open_state(controller, true);
                    output.filter_on = false;
                    output.drain_open = true;
                    output.state = CONTROLLER_STATE_DRAINING;
                    output.state_name = "STATE DRAINING";
                    output.changed = true;
                    output.timed_out = false;
                } else {
                    /* Still in settling but not drained */
                    if (input.now_ms - controller->settling_started_ms >= CONTROLLER_SETTLING_MS) {
                        /* Drain open after 400ms of settling */
                        controller_set_drain_open_state(controller, true);
                        output.filter_on = false;
                        output.drain_open = true;
                        output.state = CONTROLLER_STATE_DRAINING;
                        output.state_name = "STATE DRAINING";
                        output.changed = true;
                        output.timed_out = false;
                    } else {
                        /* Still settling */
                        if (input.turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU && input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                            controller_set_clear_streak(controller, input.turbidity_ntu);
                            output.filter_on = false;
                            output.drain_open = false;
                            output.state = CONTROLLER_STATE_SAFE_IDLE;
                            output.state_name = "STATE SAFE_IDLE";
                            output.changed = true;
                            output.timed_out = false;
                        } else {
                            /* Turbidity > 35 or level < min during settling - reset streak */
                            controller->clear_streak_count = 0;
                            output.filter_on = false;
                            output.drain_open = false;
                            output.state = CONTROLLER_STATE_SAFE_IDLE;
                            output.state_name = "STATE SAFE_IDLE";
                            output.changed = true;
                            output.timed_out = false;
                        }
                    }
                }
            } else {
                /* Clear streak not yet reached but in filtering */
                if (input.turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller_set_clear_streak(controller, input.turbidity_ntu);
                } else {
                    controller->clear_streak_count = 0;
                }
                output.filter_on = true;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = "STATE FILTERING";
                output.changed = true;
                output.timed_out = false;
            }
        }

    } else if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        /* Timeout condition */
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        output.timed_out = true;
        return output;
    }

    /* No valid input - safe idle */
    controller_set_safe_idle(controller);
    output.filter_on = false;
    output.drain_open = false;
    output.state = CONTROLLER_STATE_SAFE_IDLE;
    output.state_name = "STATE SAFE_IDLE";
    output.changed = true;
    output.timed_out = false;

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

